static void
findRangeK_omp( long height,
                knode *knodesD,
                long knodes_elem,
                long *currKnodeD,
                long *offsetD,
                long *lastKnodeD,
                long *offset_2D,
                int *startD,
                int *endD,
                int *RecstartD,
                int *ReclenD,
                int numBlocks,
                int threadsPerBlock)
{
	int bid;

	#pragma omp parallel for private(bid) schedule(static)
	for (bid = 0; bid < numBlocks; bid++) {

		int i;
		for (i = 0; i < height; i++) {
			long curr = currKnodeD[bid];
			long last = lastKnodeD[bid];
			long new_offset = offsetD[bid];
			long new_offset_2 = offset_2D[bid];

			int thid;
			for (thid = 0; thid < threadsPerBlock; thid++) {
				if ((knodesD[curr].keys[thid] <= startD[bid]) &&
				    (knodesD[curr].keys[thid + 1] > startD[bid])) {
					if (knodesD[curr].indices[thid] < knodes_elem) {
						new_offset = knodesD[curr].indices[thid];
					}
				}
				if ((knodesD[last].keys[thid] <= endD[bid]) &&
				    (knodesD[last].keys[thid + 1] > endD[bid])) {
					if (knodesD[last].indices[thid] < knodes_elem) {
						new_offset_2 = knodesD[last].indices[thid];
					}
				}
			}

			offsetD[bid] = new_offset;
			offset_2D[bid] = new_offset_2;
			currKnodeD[bid] = offsetD[bid];
			lastKnodeD[bid] = offset_2D[bid];
		}

		{
			long curr = currKnodeD[bid];
			int thid;
			for (thid = 0; thid < threadsPerBlock; thid++) {
				if (knodesD[curr].keys[thid] == startD[bid]) {
					RecstartD[bid] = knodesD[curr].indices[thid];
				}
			}
		}

		{
			long last = lastKnodeD[bid];
			int thid;
			for (thid = 0; thid < threadsPerBlock; thid++) {
				if (knodesD[last].keys[thid] == endD[bid]) {
					ReclenD[bid] = knodesD[last].indices[thid] - RecstartD[bid] + 1;
				}
			}
		}
	}
}

